+    for (const id of activeTimers) {
+      window.clearTimeout(id)
+      window.clearInterval(id)
+    }
+    activeTimers.clear()
+  }
+
+  return { safeSetTimeout, safeClearTimeout, safeSetInterval, safeClearInterval, clearAll }
 }

